import{_ as a,m as r,k as i,ah as s}from"./chunks/framework.HEc25T99.js";const h=JSON.parse('{"title":"Notes de version","description":"","frontmatter":{},"headers":[],"relativePath":"fr/release-notes.md","filePath":"src/fr/release-notes.md"}'),t={name:"fr/release-notes.md"};function o(n,e,l,d,u,v){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="notes-de-version" tabindex="-1">Notes de version <a class="header-anchor" href="#notes-de-version" aria-label="Permalink to &quot;Notes de version&quot;">​</a></h1><h2 id="v0-9-2-juin-2026" tabindex="-1">v0.9.2 - Juin 2026 <a class="header-anchor" href="#v0-9-2-juin-2026" aria-label="Permalink to &quot;v0.9.2 - Juin 2026&quot;">​</a></h2><p>Les liens des éléments de menu sont désormais plus flexibles à configurer. Corrections de bugs mineurs. Mises à jour de plusieurs bibliothèques internes.</p><h2 id="v0-9-1-—-mai-2026" tabindex="-1">v0.9.1 — Mai 2026 <a class="header-anchor" href="#v0-9-1-—-mai-2026" aria-label="Permalink to &quot;v0.9.1 — Mai 2026&quot;">​</a></h2><p>Remplacement du sélecteur de couleurs par une version plus fiable. Certains boutons d&#39;action restent désormais visibles lors du défilement de la page. Mises à jour de plusieurs bibliothèques internes.</p><h2 id="v0-9-0-—-mai-2026" tabindex="-1">v0.9.0 — Mai 2026 <a class="header-anchor" href="#v0-9-0-—-mai-2026" aria-label="Permalink to &quot;v0.9.0 — Mai 2026&quot;">​</a></h2><p>Refonte partielle de la mise en page principale. Amélioration de l&#39;affichage des pages d&#39;actualités. Les barres de recherche sont désormais harmonisées dans toute l&#39;application. Améliorations générales de la responsivité.</p><h2 id="v0-8-5-—-avril-2026" tabindex="-1">v0.8.5 — Avril 2026 <a class="header-anchor" href="#v0-8-5-—-avril-2026" aria-label="Permalink to &quot;v0.8.5 — Avril 2026&quot;">​</a></h2><p>Remplacement d&#39;une bibliothèque de chiffrement interne par une alternative plus légère et activement maintenue. Meilleure gestion des erreurs. Ajout de l&#39;autocomplétion sur les formulaires de connexion. Mises à jour de plusieurs bibliothèques internes.</p><h2 id="v0-8-4-—-avril-2026" tabindex="-1">v0.8.4 — Avril 2026 <a class="header-anchor" href="#v0-8-4-—-avril-2026" aria-label="Permalink to &quot;v0.8.4 — Avril 2026&quot;">​</a></h2><p>Amélioration de la gestion du menu de navigation : nouveau formulaire de création d&#39;éléments, prise en charge de plusieurs types d&#39;éléments et diverses corrections. Les pages nouvellement créées apparaissent désormais automatiquement en bas de la liste.</p><h2 id="v0-8-3-—-avril-2026" tabindex="-1">v0.8.3 — Avril 2026 <a class="header-anchor" href="#v0-8-3-—-avril-2026" aria-label="Permalink to &quot;v0.8.3 — Avril 2026&quot;">​</a></h2><p>Correction d&#39;un bug avec l&#39;importation de fichiers dans la médiathèque. Mises à jour de plusieurs bibliothèques internes.</p><h2 id="v0-8-2-—-avril-2026" tabindex="-1">v0.8.2 — Avril 2026 <a class="header-anchor" href="#v0-8-2-—-avril-2026" aria-label="Permalink to &quot;v0.8.2 — Avril 2026&quot;">​</a></h2><p>Les langues disponibles peuvent désormais être configurées directement depuis les paramètres de l&#39;application.</p><h2 id="v0-8-1-—-avril-2026" tabindex="-1">v0.8.1 — Avril 2026 <a class="header-anchor" href="#v0-8-1-—-avril-2026" aria-label="Permalink to &quot;v0.8.1 — Avril 2026&quot;">​</a></h2><p>Diverses corrections du système de plugins. Mises à jour de plusieurs bibliothèques internes.</p><h2 id="v0-8-0-—-mars-2026" tabindex="-1">v0.8.0 — Mars 2026 <a class="header-anchor" href="#v0-8-0-—-mars-2026" aria-label="Permalink to &quot;v0.8.0 — Mars 2026&quot;">​</a></h2><p>Nouvelle page de gestion des plugins avec une activation et désactivation améliorées. Améliorations des performances.</p><h2 id="v0-7-7-—-mars-2026" tabindex="-1">v0.7.7 — Mars 2026 <a class="header-anchor" href="#v0-7-7-—-mars-2026" aria-label="Permalink to &quot;v0.7.7 — Mars 2026&quot;">​</a></h2><p>Améliorations de la gestion du contenu : recherche de pages dans la barre latérale, possibilité de réordonner les pages et prise en charge des titres de liens dans les sections de page.</p><h2 id="v0-7-5-—-mars-2026" tabindex="-1">v0.7.5 — Mars 2026 <a class="header-anchor" href="#v0-7-5-—-mars-2026" aria-label="Permalink to &quot;v0.7.5 — Mars 2026&quot;">​</a></h2><p>En mode développement, les données brutes des éléments de contenu sont désormais accessibles pour faciliter le débogage. Mises à jour de plusieurs bibliothèques internes.</p><h2 id="v0-7-4-—-fevrier-2026" tabindex="-1">v0.7.4 — Février 2026 <a class="header-anchor" href="#v0-7-4-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.4 — Février 2026&quot;">​</a></h2><p>Améliorations de l&#39;interface responsive pour toutes les tailles d&#39;écran. Correction d&#39;un bug lié aux paramètres de structure de données. Mises à jour majeures de bibliothèques internes.</p><h2 id="v0-7-3-—-fevrier-2026" tabindex="-1">v0.7.3 — Février 2026 <a class="header-anchor" href="#v0-7-3-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.3 — Février 2026&quot;">​</a></h2><p>Nombreuses améliorations de l&#39;éditeur visuel : meilleure gestion des champs de section et du générateur de formulaires.</p><h2 id="v0-7-2-—-fevrier-2026" tabindex="-1">v0.7.2 — Février 2026 <a class="header-anchor" href="#v0-7-2-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.2 — Février 2026&quot;">​</a></h2><p>Améliorations de l&#39;assistant de configuration initiale : meilleure création de base de données et corrections de bugs.</p><h2 id="v0-7-1-—-fevrier-2026" tabindex="-1">v0.7.1 — Février 2026 <a class="header-anchor" href="#v0-7-1-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.1 — Février 2026&quot;">​</a></h2><p>Le sélecteur d&#39;icônes dans les paramètres de l&#39;application peut désormais être configuré pour retourner le nom de l&#39;icône.</p><h2 id="v0-7-0-—-fevrier-2026" tabindex="-1">v0.7.0 — Février 2026 <a class="header-anchor" href="#v0-7-0-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.0 — Février 2026&quot;">​</a></h2><p>Refonte complète du système d&#39;accès et d&#39;authentification avec une architecture plus claire.</p><h2 id="v0-6-x-—-decembre-2025-–-janvier-2026" tabindex="-1">v0.6.x — Décembre 2025 – Janvier 2026 <a class="header-anchor" href="#v0-6-x-—-decembre-2025-–-janvier-2026" aria-label="Permalink to &quot;v0.6.x — Décembre 2025 – Janvier 2026&quot;">​</a></h2><p>Gestion des métadonnées et de la visibilité des vidéos. Corrections de bugs dans l&#39;éditeur visuel.</p><h2 id="v0-6-0-—-decembre-2025" tabindex="-1">v0.6.0 — Décembre 2025 <a class="header-anchor" href="#v0-6-0-—-decembre-2025" aria-label="Permalink to &quot;v0.6.0 — Décembre 2025&quot;">​</a></h2><p>Lancement de l&#39;éditeur visuel : gérez les sections de page directement depuis l&#39;interface via une barre latérale dédiée.</p><h2 id="v0-5-0-rc-x-—-septembre–novembre-2025" tabindex="-1">v0.5.0-rc.x — Septembre–Novembre 2025 <a class="header-anchor" href="#v0-5-0-rc-x-—-septembre–novembre-2025" aria-label="Permalink to &quot;v0.5.0-rc.x — Septembre–Novembre 2025&quot;">​</a></h2><p>Améliorations progressives de l&#39;éditeur visuel : copie de données entre sections, réorganisation par glisser-déposer, mode prévisualisation et meilleure gestion des modèles de contenu.</p><h2 id="v0-5-0-rc-1-—-septembre-2025" tabindex="-1">v0.5.0-rc.1 — Septembre 2025 <a class="header-anchor" href="#v0-5-0-rc-1-—-septembre-2025" aria-label="Permalink to &quot;v0.5.0-rc.1 — Septembre 2025&quot;">​</a></h2><p>Mise à jour majeure : refonte de la mise en page principale, améliorations de la médiathèque et mise à niveau de l&#39;éditeur de texte enrichi.</p><h2 id="v0-0-17-—-aout-2025" tabindex="-1">v0.0.17 — Août 2025 <a class="header-anchor" href="#v0-0-17-—-aout-2025" aria-label="Permalink to &quot;v0.0.17 — Août 2025&quot;">​</a></h2><p>Améliorations des performances : chargement plus rapide des articles, newsletters et autres contenus.</p><h2 id="v0-0-16-—-mai-2025" tabindex="-1">v0.0.16 — Mai 2025 <a class="header-anchor" href="#v0-0-16-—-mai-2025" aria-label="Permalink to &quot;v0.0.16 — Mai 2025&quot;">​</a></h2><p>Introduction du système de plugins.</p><h2 id="v0-0-14-—-avril-2025" tabindex="-1">v0.0.14 — Avril 2025 <a class="header-anchor" href="#v0-0-14-—-avril-2025" aria-label="Permalink to &quot;v0.0.14 — Avril 2025&quot;">​</a></h2><p>Prise en charge de la traduction automatique dans les champs multilingues. Fonctionnalité d&#39;import et d&#39;export d&#39;utilisateurs.</p><h2 id="v0-0-13-—-mars-2025" tabindex="-1">v0.0.13 — Mars 2025 <a class="header-anchor" href="#v0-0-13-—-mars-2025" aria-label="Permalink to &quot;v0.0.13 — Mars 2025&quot;">​</a></h2><p>Nouveaux types de champs dans le générateur de formulaires : date/heure, plages horaires, mois, trimestre et semaine.</p><h2 id="v0-0-10-—-mars-2025" tabindex="-1">v0.0.10 — Mars 2025 <a class="header-anchor" href="#v0-0-10-—-mars-2025" aria-label="Permalink to &quot;v0.0.10 — Mars 2025&quot;">​</a></h2><p>Ajout des champs liste et liste multilingue dans le générateur de formulaires.</p><h2 id="v0-0-8-—-fevrier-2025" tabindex="-1">v0.0.8 — Février 2025 <a class="header-anchor" href="#v0-0-8-—-fevrier-2025" aria-label="Permalink to &quot;v0.0.8 — Février 2025&quot;">​</a></h2><p>Améliorations de l&#39;interface mobile. Limite configurable sur les sélections multiples.</p><h2 id="v0-0-5-—-janvier-2025" tabindex="-1">v0.0.5 — Janvier 2025 <a class="header-anchor" href="#v0-0-5-—-janvier-2025" aria-label="Permalink to &quot;v0.0.5 — Janvier 2025&quot;">​</a></h2><p>Nombreuses corrections et nouvelles fonctionnalités : gestion des permaliens, sélecteur de médias, mise à jour automatique des sections, affichage de la position des sections et corrections de pagination.</p><h2 id="v0-0-2-—-janvier-2025" tabindex="-1">v0.0.2 — Janvier 2025 <a class="header-anchor" href="#v0-0-2-—-janvier-2025" aria-label="Permalink to &quot;v0.0.2 — Janvier 2025&quot;">​</a></h2><p>Première version publique : tableau de bord avec carte des visites et gestion des vidéos.</p>',57)])])}const m=a(t,[["render",o]]);export{h as __pageData,m as default};
